function firstItem(name) { try { const items = $items(name); return items[0] || { json: { error: 'node produced no items' } }; } catch (error) { return { json: { error: error.message } }; } }
function cleanJson(json) { const copy = { ...(json || {}) }; delete copy.url; delete copy.token; return copy; }
function statusFor(name, options = {}) { const input = firstItem('Prepare Matrix Inputs').json || {}; if (options.requiredInput && !input[options.requiredInput]) { return { operation: options.operation, status: 'skipped_missing_input', node: name, details: { missingInput: options.requiredInput } }; } const item = firstItem(name); const json = item.json || {}; const hasBinary = Boolean(item.binary && Object.keys(item.binary).length > 0); const ok = !json.error && (json.ok === true || options.passWhen?.(json, hasBinary)); return { operation: options.operation, status: ok ? 'passed' : 'failed', node: name, hasBinary, resultKeys: Object.keys(json).filter((key) => key !== 'url').sort(), details: ok ? cleanJson(json) : { error: json.error || json.description || 'No success marker in node output', result: cleanJson(json) } }; }
const checks = [statusFor('Bot Get Self', { operation: 'bot.getSelf' }), statusFor('Chat Get Info', { operation: 'chat.getInfo' }), statusFor('Send Text', { operation: 'message.sendText' }), statusFor('Edit Text', { operation: 'message.editText' }), statusFor('Send File', { operation: 'message.sendFile' }), statusFor('File Get Info', { operation: 'file.getInfo', passWhen: (json) => Boolean(json.filename || json.type || json.size || json.ok === true) }), statusFor('File Download', { operation: 'file.download', passWhen: (json, hasBinary) => hasBinary && Boolean(json.filename || json.type || json.size || json.ok === true) }), statusFor('Send Voice', { operation: 'message.sendVoice' }), statusFor('Answer Callback Query', { operation: 'callback.answerCallbackQuery', requiredInput: 'callbackQueryId' }), statusFor('Delete Text Message', { operation: 'message.deleteMessages.text' }), statusFor('Delete File Message', { operation: 'message.deleteMessages.file' }), statusFor('Delete Voice Message', { operation: 'message.deleteMessages.voice' })];
const input = firstItem('Prepare Matrix Inputs').json || {}; const summary = checks.reduce((acc, check) => { acc[check.status] = (acc[check.status] || 0) + 1; return acc; }, {});
return [{ json: { runId: input.runId, label: input.label, chatIdProvided: Boolean(input.chatId), fileIdFallbackProvided: Boolean(input.fileId), callbackQueryIdProvided: Boolean(input.callbackQueryId), summary, checks } }];
